    fun i(message: String, vararg args: Any?) = Timber.tag(TAG_PREFIX).i(message, *args)
    fun w(message: String, vararg args: Any?) = Timber.tag(TAG_PREFIX).w(message, *args)
    fun e(message: String, vararg args: Any?) = Timber.tag(TAG_PREFIX).e(message, *args)
    fun e(t: Throwable, message: String = "Unhandled exception", vararg args: Any?) =
        Timber.tag(TAG_PREFIX).e(t, message, *args)

    fun logAuthAttempt(usernameOrId: String, success: Boolean, reason: String? = null) {
