    fun logApiResponse(code: Int, message: String, body: String?) {
        Timber.tag("API").v(
            "Response code=%d message=%s body=%s",
            code,
            message,
            body ?: "<empty>"
        )
    }

    fun logException(t: Throwable, context: String? = null) {
        if (context.isNullOrBlank()) {
            Timber.tag("EXCEPTION").e(t)
        } else {
