    private fun Any?.toSafeLogString(): String = when (this) {
        null -> "null"
        is Map<*, *> -> entries.joinToString(
            prefix = "{",
            postfix = "}"
        ) { (k, v) -> "${k.safeToString()}=${v.safeToString()}" }
        is Iterable<*> -> joinToString(prefix = "[", postfix = "]") { it.safeToString() }
        is Array<*> -> joinToString(prefix = "[", postfix = "]") { it.safeToString() }
        else -> safeToString()
    }

    private fun Any?.safeToString(): String = when (this) {
        null -> "null"
        is CharSequence, is Number, is Boolean, is Enum<*> -> toString()
        else -> toString()
    }

    private class DebugTree : Timber.DebugTree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            if (t != null) {
                super.log(priority, tag, "$message\n${Log.getStackTraceString(t)}", null)
            } else {
                super.log(priority, tag, message, null)
            }
        }

        override fun createStackElementTag(element: StackTraceElement): String {
            return "APP:${element.fileName}:${element.lineNumber}"
        }
    }

    private class ReleaseTree : Timber.Tree() {
        override fun isLoggable(tag: String?, priority: Int): Boolean {
            return priority >= Log.INFO
