        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            val androidTag = tag ?: TAG_PREFIX
            when (priority) {
                Log.ERROR -> Log.e(androidTag, message, t)
                Log.WARN -> Log.w(androidTag, message, t)
                Log.INFO -> Log.i(androidTag, message)
                else -> Log.d(androidTag, message)
            }
        }
    }
}

class LoggingApiInterceptor : Interceptor {
    @Throws(IOException::class)
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        logRequest(request)
        val response: Response = try {
            chain.proceed(request)
        } catch (t: Throwable) {
            AppLogger.logException(t, "API call failed: ${request.method} ${request.url}")
            throw t
        }

        val responseBodyString = response.peekBody(Long.MAX_VALUE).string()
        AppLogger.logApiResponse(
            code = response.code,
            message = response.message,
            body = responseBodyString
        )
        return response
    }

    private fun logRequest(request: Request) {
        val headers = buildMap {
            for (name in request.headers.names()) {
                put(name, request.header(name).orEmpty())
            }
        }
        val bodyString = try {
            request.body?.let { body ->
                val buffer = okio.Buffer()
                body.writeTo(buffer)
                buffer.readUtf8()
            }
        } catch (_: Throwable) {
            "<unavailable>"
        }

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = headers,
            body = bodyString
        )
    }
}

