package com.example.app

import android.app.Application
import com.example.app.logging.AppLogger
import okhttp3.OkHttpClient

class MyApplication : Application() {
    override fun onCreate() {
        super.onCreate()
        AppLogger.init(this, enableVerbose = BuildConfig.DEBUG)
    }

    fun createHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(LoggingApiInterceptor())
            .build()
    }
}

package com.example.app.logging

import androidx.annotation.Keep

@Keep
class CrashLogger : Thread.UncaughtExceptionHandler {
    private val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()

    override fun uncaughtException(t: Thread, e: Throwable) {
        AppLogger.logException(e, "Unhandled crash on thread=${t.name}")
        defaultHandler?.uncaughtException(t, e)
    }
}